    rayTrap[i].xOffset=432; rayTrap[i].yOffset=0
    rayTrap[i].sensorTime=0; rayTrap[i].timeToON=1000000; rayTrap[i].timeToOFF=1000000
  }
}
else if room=rBT_ZeroC
{
  mapEventProg=0
  mapEventTime=0
}
else if room=rBT_ZeroD
{
  mapEventProg=0
  mapEventTime=0
